# %%
# Se definen los países y sus columnas correspondientes
paises = {
    'Estados_Unidos': {'vol': 'Estados Unidos 🇺🇸_volatilidad', 'sent': 'Estados Unidos 🇺🇸'},
    'Israel': {'vol': 'Israel 🇮🇱_volatilidad', 'sent': 'Israel 🇮🇱'},
    'Rusia': {'vol': 'Rusia 🇷🇺_volatilidad', 'sent': 'Rusia 🇷🇺'}
}

# Diccionarios para almacenar los DataFrames en la memoria de Python
dfs_promedios = {}
dfs_modelos = {}

for pais_nombre, columnas in paises.items():
    col_vol = columnas['vol']
    col_sent = columnas['sent']

    # =========================================================
    # 1. DATASET DE PROMEDIOS
    # =========================================================
    df_promedio = df_finance_and_sent.groupby(col_sent)[col_vol].mean().reset_index()
    df_promedio.columns = ['Categoria', 'Volatilidad promedio']

    # Multiplicamos por 100 y añadimos el símbolo '%' para formato Excel
    df_promedio['Volatilidad promedio'] = (df_promedio['Volatilidad promedio'] * 100).round(2)

    # Guardamos en el diccionario
    dfs_promedios[pais_nombre] = df_promedio

    # Exportar a CSV
    nombre_archivo_promedio = f"{pais_nombre}_promedios.csv"
    df_promedio.to_csv(nombre_archivo_promedio, index=False, encoding='utf-8-sig')

    # =========================================================
    # 2. DATASET DEL MODELO (LAG1 + Dummies sin NEU)
    # =========================================================
    df_temp = df_finance_and_sent[[col_vol, col_sent]].copy()

    # Crear el LAG1
    df_temp['LAG1'] = df_temp[col_vol].shift(1)

    # Crear variables dummy
    dummies = pd.get_dummies(df_temp[col_sent], dtype=int)
    dummies.columns = [f"{col}" for col in dummies.columns]

    # Se elimina NEU
    if 'NEU' in dummies.columns:
        dummies.drop(columns=['NEU'], inplace=True)

    # Unir todo
    df_modelo = pd.concat([df_temp['LAG1'], dummies, df_temp[col_vol]], axis=1)
    df_modelo.rename(columns={col_vol: 'Volatilidad (Y)'}, inplace=True)

    # Eliminar el primer mes porque el LAG1 queda vacío
    df_modelo.dropna(inplace=True)

    # Quitar columnas dummy que no tengan datos (por ejemplo, si no hubo POS)
    for col in dummies.columns:
        if col in df_modelo.columns and df_modelo[col].sum() == 0:
            df_modelo.drop(columns=[col], inplace=True)

    # Guardamos en el diccionario
    dfs_modelos[pais_nombre] = df_modelo

    # Exportar a CSV
    nombre_archivo_modelo = f"{pais_nombre}_modelo.csv"
    df_modelo.to_csv(nombre_archivo_modelo, index=False, encoding='utf-8-sig')

    # Confirmación en pantalla para saber que funcionó correctamente
    print(f"=============================")
    print(f"--- {pais_nombre} ---")
    print(f"=============================")
    print(f"\n--- Df Modelo ---")
    print(df_modelo.head(5))
    print(f"\n--- Df promedio ---")
    print(df_promedio.head(5))
    print("\n")

# %% [markdown]
# 
# 
# Al momento de seleccionar los datos para este análisis, el enfoque principal fue capturar fielmente cómo el contexto geopolítico impacta el riesgo de los mercados. Por esta razón, elegimos la volatilidad mensual como nuestra variable principal, en escencia es el termómetro perfecto para medir la incertidumbre de los inversores. Para explicar esos movimientos, incorporamos el sentimiento de las noticias como variables explicativas. Esto nos permite traducir eventos cualitativos del mundo real, como tensiones políticas o conflictos, en datos que podemos medir y relacionar directamente con la economía.
# 
# En cuanto al manejo de la muestra, decidimos no aplicar técnicas de muestreo aleatorio ni recortar el tamaño de los datos temporalmente. En el análisis financiero, el orden cronológico de los eventos es sagrado, y alterar esa secuencia arruinaría la capacidad de ver cómo una noticia hoy afecta el mercado mañana. Lo que sí hicimos fue aplicar un filtrado estructural: separamos la información en tres bases de datos distintas (una para Estados Unidos, otra para Israel y otra para Rusia). Esto es fundamental porque la realidad macroeconómica de cada país es única; un evento que dispara la volatilidad en Rusia no necesariamente se comporta igual en el mercado estadounidense. Además, mantuvimos intactos los valores atípicos (los picos extremos de volatilidad) porque, lejos de ser errores, son exactamente los "shocks" geopolíticos que estamos intentando entender. El único filtro real que aplicamos fue eliminar el primer mes de nuestra serie de tiempo, ya que al calcular el dato del mes anterior, esa primera fila quedaba en blanco.
# 
# Finalmente, la elección de qué variables incluir o excluir respondió a razones puramente estadísticas para asegurar que el modelo funcionara bien. Decidimos incluir la volatilidad del mes anterior (el LAG1) porque los mercados tienen "memoria"; normalmente, a un mes muy inestable le sigue otro igual de tenso. Para poder meter las noticias de texto en un modelo matemático, las convertimos en variables binarias (ceros y unos). Sin embargo, tuvimos que excluir intencionalmente la categoría de noticias "Neutras". Esto se hace para evitar un problema matemático conocido como la trampa de las variables ficticias; al dejar lo neutro por fuera, se convierte en nuestra base de comparación. Por último, también aseguramos que si un país no tuvo, por ejemplo, ninguna noticia positiva en todo el periodo, esa columna se eliminara automáticamente para no "romper" los cálculos de la regresión.

