## DISTRIBUCIÓN – VARIABLES CONTINUAS (Y)
#LAG1 Y VOLATILIDAD
from scipy.stats import gaussian_kde

for pais, df in dfs_modelos.items():

    lag1 = df['LAG1'].dropna()
    vol  = df['Volatilidad (Y)'].dropna()

    fig, axes = plt.subplots(1, 2, figsize=(14, 5))
    fig.suptitle(f'{pais} – Distribución de variables continuas', fontsize=13, fontweight='bold')

    for ax, (nombre, serie, color) in zip(axes, [
        ('LAG1',            lag1, 'steelblue'),
        ('Volatilidad (Y)', vol,  '#e74c3c')
    ]):
        ax.hist(serie, bins=6, color=color, alpha=0.4, density=True, edgecolor='white', label='Histograma')
        xs  = np.linspace(serie.min(), serie.max(), 200)
        kde = gaussian_kde(serie)
        ax.plot(xs, kde(xs), color=color, lw=2.5, label='KDE')
        ax.axvline(serie.mean(),   color='black',  lw=1.5, linestyle='--', label=f'Media    = {serie.mean():.4f}')
        ax.axvline(serie.median(), color='orange', lw=1.5, linestyle=':',  label=f'Mediana = {serie.median():.4f}')
        ax.set_title(nombre, fontsize=11, fontweight='bold')
        ax.set_xlabel('Valor')
        ax.set_ylabel('Densidad')
        ax.legend(fontsize=8)
        ax.grid(True, linestyle='--', alpha=0.4)

    plt.tight_layout()
    plt.show()

    print(f"\n  {pais}")
    print(f"  {'':20} {'LAG1':>10} {'Volatilidad':>12}")
    print(f"  {'Media':20} {lag1.mean():>10.4f} {vol.mean():>12.4f}")
    print(f"  {'Mediana':20} {lag1.median():>10.4f} {vol.median():>12.4f}")
    print(f"  {'Std':20} {lag1.std():>10.4f} {vol.std():>12.4f}")
    print(f"  {'Asimetría':20} {lag1.skew():>10.4f} {vol.skew():>12.4f}")
    print(f"  {'Curtosis':20} {lag1.kurt():>10.4f} {vol.kurt():>12.4f}")

