# Q-Q PLOT - VARIABLES CONTÍNUAS
#Se compara contra distribución normal
import plotly.graph_objects as go
from plotly.subplots import make_subplots
from scipy.stats import probplot
import numpy as np

colores = {
    'LAG1':            'steelblue',
    'Volatilidad (Y)': '#e74c3c'
}

for pais, df in dfs_modelos.items():

    lag1 = df['LAG1'].dropna().values
    vol  = df['Volatilidad (Y)'].dropna().values

    fig = make_subplots(
        rows=1, cols=2,
        subplot_titles=[
            'Dato Observado LAG 1',
            'Dato Observado Volatilidad Y'
        ],
        horizontal_spacing=0.12
    )

    for col_idx, (nombre, serie, color) in enumerate([
        ('Dato Observado LAG 1',        lag1, colores['LAG1']),
        ('Dato Observado Volatilidad Y', vol,  colores['Volatilidad (Y)'])
    ], start=1):

        (osm, osr), (slope, intercept, _) = probplot(serie, dist='norm')
        osm = np.array(osm)
        osr = np.array(osr)
        linea = slope * osm + intercept

        meses = [f'M{i+1}' for i in range(len(osm))]

        #  Puntos
        fig.add_trace(
            go.Scatter(
                x=osm, y=osr,
                mode='markers+text',
                marker=dict(
                    color=color, size=10,
                    line=dict(color='white', width=1.5),
                    opacity=0.85
                ),
                text=meses,
                textposition='top right',
                textfont=dict(size=9, color='grey'),
                name=nombre,
                legendgroup=nombre,
                hovertemplate=(
                    "<b>%{text}</b><br>"
                    "<i>M = mes de observación</i><br>"
                    "Cuantil teórico: %{x:.4f}<br>"
                    "Cuantil observado: %{y:.4f}<extra></extra>"
                ),
                showlegend=True
            ),
            row=1, col=col_idx
        )

        #  Línea normal teórica
        fig.add_trace(
            go.Scatter(
                x=osm, y=linea,
                mode='lines',
                line=dict(color='black', width=2, dash='dash'),
                name='Línea normal teórica',
                legendgroup='linea',
                hoverinfo='skip',
                showlegend=col_idx == 1
            ),
            row=1, col=col_idx
        )

        #  Ejes
        fig.update_xaxes(
            title_text='Cuantiles teóricos',
            title_font=dict(size=11),
            gridcolor='lightgrey', gridwidth=0.5,
            row=1, col=col_idx
        )
        fig.update_yaxes(
            title_text='Cuantiles observados' if col_idx == 1 else '',
            title_font=dict(size=11),
            gridcolor='lightgrey', gridwidth=0.5,
            row=1, col=col_idx
        )

    # Layout por país
    fig.update_layout(
        title=dict(
            text=f'{pais.replace("_", " ")} , Q-Q Plot (Normalidad)',
            font=dict(size=15, color='#222'),
            x=0.5, xanchor='center'
        ),
        height=450,
        width=950,
        plot_bgcolor='white',
        paper_bgcolor='white',
        font=dict(family='Arial', size=11),
        margin=dict(t=100, b=80, l=60, r=30),
        legend=dict(
            orientation='h',
            x=0.5, xanchor='center',
            y=-0.15
        ),
        hoverlabel=dict(
            bgcolor='white',
            bordercolor='grey',
            font_size=12
        ),
        annotations=[
            dict(
                text="<b>M</b> = Mes",
                xref="paper", yref="paper",
                x=0, y=-0.22,
                showarrow=False,
                font=dict(size=10, color="grey"),
                align="left"
            )
        ]
    )

    fig.show()

