#Prueba de normalidad para los dataset
def prueba_normalidad(df):
    for pais,data in df.items():
        st,p_val = scipy.stats.shapiro(data['Volatilidad (Y)'])
        if p_val <0.05:
            print(f"La volatilidad NO tiene una distribución normal para el índice bursátil de {pais}\n con una significancia de {p_val:.3f}\n")
        else:
              print(f"La volatilidad tiene una distribución normal para el índice bursátil de {pais}\n con una significancia de {p_val:.3f}\n")
prueba_normalidad(dfs_modelos)

